mapper.select:
SELECT id, date, ticker, blogger, sentiment_score as sentimentScore, horizon, strategy, raw_content as rawContent, channel_id as channelId, channel_name as channelName, message_time as messageTime, created_at as createdAt, updated_at as updatedAt
FROM blogger_raw_sentiments
WHERE ticker = #{ticker}
AND date = #{date}
ORDER BY blogger

SELECT id, date, ticker, blogger, sentiment_score as sentimentScore, horizon, strategy, raw_content as rawContent, channel_id as channelId, channel_name as channelName, message_time as messageTime, created_at as createdAt, updated_at as updatedAt
FROM blogger_raw_sentiments
WHERE ticker = #{ticker}
AND date  >=  #{startTime}
AND date  <=  #{endTime}
ORDER BY date DESC, blogger

